window.SmartRisk=window.SmartRisk||{};(function(){const routes=new Map();const n=p=>{const c=String(p||"/").replace(/^#/,"").trim();return c.startsWith("/")?c:`/${c}`};const current=()=>n(location.hash||SmartRisk.Config.defaultRoute);async function resolve(){const p=current(),r=routes.get(p),c=document.getElementById("app-content");SmartRisk.Loader.show("Cargando vista…");try{if(!r){c.innerHTML='<section class="panel module-placeholder"><div><span class="badge badge-danger">404</span><h2>Ruta no encontrada</h2><a class="btn btn-primary" href="#/dashboard">Volver</a></div></section>';return}c.innerHTML=await r.render();c.focus({preventScroll:true});SmartRisk.Utils.setTitle(r.title);SmartRisk.Sidebar.setActive(p);SmartRisk.Navbar.update(p);r.bind?.()}finally{SmartRisk.Loader.hide()}}SmartRisk.Router={register(r){routes.set(n(r.path),r)},start(){addEventListener("hashchange",resolve);if(!location.hash)location.hash=SmartRisk.Config.defaultRoute;else resolve()},current}})();